INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-6f0ba476-moex-00245', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲男乙女為夫妻，有一子丙。丙已成年，未婚無子。甲之母丁尚生存。若甲、丙同時死亡，下列 關於丙之遺產繼承之敘述，何者正確？', '["乙繼承甲遺產三分之二、丁繼承甲遺產三分之一；乙繼承丙遺產全部", "甲、乙共同繼承丙之遺產，然後再由乙單獨繼承甲之全部遺產", "乙繼承甲遺產二分之一、丁繼承甲遺產二分之一；乙繼承丙遺產三分之二、丁繼承丙遺產三分 之一", "乙繼承甲遺產二分之一、丁繼承甲遺產二分之一；乙繼承丙遺產全部"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00246', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '密封遺囑為要式行為，若不具備法定方式，其效力如何？', '["遺囑效力未定，得隨時拒絕承認", "須經遺囑人的承認後，並經公證，始發生效力", "經法院認可後，得為有效", "密封遺囑雖然無效，然若具備自書遺囑之方式者，有自書遺囑之效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00247', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲為乙之父。關於甲乙之扶養關係，下列敘述何者正確？', '["乙成年後，甲因負擔對乙之扶養義務而不能維持自己生活者，得減輕其義務", "乙成年後，對甲不予扶養，即當然喪失對甲之繼承權", "乙未成年時，不服甲之管教，對甲故意為重大侮辱，甲不得請求減輕對乙之扶養義務", "乙未成年時，甲未盡扶養義務，因扶養請求權各自獨立，甲當然得請求成年後之乙為扶養，乙 不得拒絕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00248', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲中年喪偶，僅有一子A。今甲死亡，留有未清償之債務數筆，以及土地、存款等財產。A有依 法開具遺產清冊，陳報法院。有關甲遺產之繼承，下列敘述何者錯誤？', '["A依法陳報法院時，法院應依公示催告程序公告，命甲之債權人於一定期限內報明其債權", "A在法院公示催告甲之債權人報明債權所定一定期限內，得對於甲之受遺贈人交付遺贈", "甲之債權人，如不於法院公示催告所定之一定期限內報明其債權，而又為A所不知者，僅得就 賸餘遺產，行使其權利", "在法院公示催告甲之債權人報明債權所定一定期限屆滿後，A 對於在該一定期限內報明之債 權及A所已知之債權，均應按其數額，比例計算，以遺產分別償還。但不得害及有優先權人 之利益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00249', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'essay', '請依學理說明稅式支出（taxexpenditure）的意義，並請以我國的綜合所
得稅為例，列舉四種常見稅式支出的型態及說明其意義。又這些不同型
態的稅式支出，對納稅義務人的價值，與其適用的邊際稅率有何關係？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00250', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'essay', '何謂租稅中立性（taxneutrality）？請以代表性家計單位為例，詳細說明
分別在有與沒有考慮休閒的情形下，政府課徵定額稅（lump sumtax）、
特產稅（excisetax）或比例所得稅時，是否符合租稅中立性？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00251', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '若社會福利函數為個人效用函數的簡單加總時，在下列以效用為納稅能力的公平原則中，何者也', '["相等絕對犧牲", "相等比例犧牲", "相等邊際犧牲", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00252', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '令一租稅函數如下：T=（Y-E）×10%，T、Y、E分別代表稅額、所得額與免稅額，且Y>E>0； 稅率為10%。關於此租稅函數累進或累退性之敘述，下列何者正確？', '["以邊際稅率與平均稅率衡量均為累進稅", "以邊際稅率與平均稅率衡量均為比例稅", "以邊際稅率衡量為累進稅，以平均稅率衡量為比例稅", "以邊際稅率衡量為比例稅，以平均稅率衡量為累進稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00253', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '在獨占市場上，市場需求曲線為直線形狀，廠商的邊際成本為固定，廠商追求利潤極大。對獨占 廠商課徵定額式（specific）或從價式（advalorem）商品稅，當稅收相同時，課徵定額式比課徵從 價式商品稅的產量為：', '["多", "相等", "少", "無法比較"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00254', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '根據哈柏格（ArnoldC.Harberger）一般均衡模型，公司所得稅在下列何種情況下較能轉嫁給資本？', '["在公司部門，勞動非為資本的良好替代品", "公司部門為相對勞力密集", "公司部門為相對資本密集", "在非公司部門，資本是勞動的良好替代品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "13c6a5c641c8", "answer_pdf_sha1": "a633ee315514", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
